// Parse incoming product data and enrich with store links
const incoming = $input.first().json;
const body = incoming.body || incoming;

// Build post URLs - combine best performing store URL
const primaryUrl = body.gumroad_url || body.etsy_url || body.payhip_url || 'https://gumroad.com';

// Inject the real product URL into captions
const enrichedSocial = {
  product_title: body.youtube_title || 'New Digital Product',

  // Inject URLs into captions
  instagram_caption: (body.ig_caption || '') + `\n\n🔗 Link in bio | Shop: ${primaryUrl}`,
  facebook_post: (body.fb_post || '') + `\n\n👇 Get it here: ${primaryUrl}`,
  tiktok_script: body.tiktok_script || '',
  pinterest_description: (body.pinterest_description || '') + ` Shop now: ${primaryUrl}`,
  youtube_title: body.youtube_title || 'Check out this digital product!',
  youtube_description: `${body.youtube_title}\n\n🔗 Get it here: ${primaryUrl}\n\n#digitalproducts #passiveincome #etsy`,

  // Store links
  gumroad_url: body.gumroad_url || '',
  etsy_url: body.etsy_url || '',
  payhip_url: body.payhip_url || '',
  primary_url: primaryUrl,

  timestamp: new Date().toISOString()
};

return [{ json: enrichedSocial }];

// Collect all social media results
const social = $('⚙️ Enrich Social Content with URLs').first().json;

const fbResult = $('📘 Post to Facebook Page').first().json;
const igResult = $('📸 Instagram — Publish Post').first().json;
const ttResult = $('🎵 Post to TikTok').first().json;
const pinResult = $('📌 Post to Pinterest').first().json;
const ytResult = $('▶️ Schedule YouTube Short').first().json;

const report = {
  product_title: social.product_title,
  posted_at: new Date().toISOString(),

  results: {
    facebook: {
      success: !!fbResult?.id,
      post_id: fbResult?.id || null
    },
    instagram: {
      success: !!igResult?.id,
      post_id: igResult?.id || null
    },
    tiktok: {
      success: ttResult?.data?.publish_id ? true : false,
      publish_id: ttResult?.data?.publish_id || null
    },
    pinterest: {
      success: !!pinResult?.id,
      pin_id: pinResult?.id || null,
      pin_url: pinResult?.id ? `https://www.pinterest.com/pin/${pinResult.id}` : null
    },
    youtube: {
      success: !!ytResult,
      note: 'Check YouTube Studio for upload status'
    }
  },

  summary: `Social posting complete for: ${social.product_title}`,
  primary_url: social.primary_url
};

return [{ json: report }];
